/* js/qrcode.min.js
 * Minimal QR generator + compatibility wrapper exposing window.QRCode.toCanvas
 * License: MIT-style (derived conceptually from common QR implementations)
 * Purpose: avoid CDN dependency on GitHub Pages / offline / blocked networks.
 */
(function(global){
  "use strict";

  // ---------- Minimal QR encoder (Version auto up to 10, EC level M) ----------
  // This is a compact, pragmatic implementation that supports byte mode (UTF-8)
  // and is intended for short payload URLs like application.html#HELLO=...
  // Not a full general-purpose QR suite, but stable for IRLid home QR use.

  function utf8Bytes(str){
    const out = [];
    for (let i=0;i<str.length;i++){
      let c = str.charCodeAt(i);
      if (c < 0x80) out.push(c);
      else if (c < 0x800){
        out.push(0xC0 | (c >> 6));
        out.push(0x80 | (c & 0x3F));
      } else if (c >= 0xD800 && c <= 0xDBFF){
        // surrogate pair
        i++;
        const c2 = str.charCodeAt(i);
        const u = 0x10000 + (((c & 0x3FF) << 10) | (c2 & 0x3FF));
        out.push(0xF0 | (u >> 18));
        out.push(0x80 | ((u >> 12) & 0x3F));
        out.push(0x80 | ((u >> 6) & 0x3F));
        out.push(0x80 | (u & 0x3F));
      } else {
        out.push(0xE0 | (c >> 12));
        out.push(0x80 | ((c >> 6) & 0x3F));
        out.push(0x80 | (c & 0x3F));
      }
    }
    return out;
  }

  // Galois field GF(256) tables for Reed-Solomon
  const GF_EXP = new Uint8Array(512);
  const GF_LOG = new Uint8Array(256);
  (function initGF(){
    let x = 1;
    for (let i=0;i<255;i++){
      GF_EXP[i] = x;
      GF_LOG[x] = i;
      x <<= 1;
      if (x & 0x100) x ^= 0x11d;
    }
    for (let i=255;i<512;i++) GF_EXP[i] = GF_EXP[i-255];
  })();

  function gfMul(a,b){
    if (a===0 || b===0) return 0;
    return GF_EXP[GF_LOG[a] + GF_LOG[b]];
  }

  function rsGeneratorPoly(deg){
    // (x - a^0)(x - a^1)...(x - a^(deg-1))
    let poly = [1];
    for (let i=0;i<deg;i++){
      const next = new Array(poly.length+1).fill(0);
      for (let j=0;j<poly.length;j++){
        next[j] ^= gfMul(poly[j], GF_EXP[i]);
        next[j+1] ^= poly[j];
      }
      poly = next;
    }
    return poly; // highest degree at end
  }

  function rsComputeECC(data, ecLen){
    const gen = rsGeneratorPoly(ecLen);
    const ecc = new Array(ecLen).fill(0);
    for (let i=0;i<data.length;i++){
      const factor = data[i] ^ ecc[0];
      ecc.shift();
      ecc.push(0);
      for (let j=0;j<ecLen;j++){
        ecc[j] ^= gfMul(gen[j], factor);
      }
    }
    return ecc;
  }

  // QR capacities (byte mode) for versions 1..10, EC level M (approx)
  // Data codewords and EC codewords for M from spec tables:
  const QR_TABLE_M = {
    1: { dataCw:16, ecCw:10, size:21 },
    2: { dataCw:28, ecCw:16, size:25 },
    3: { dataCw:44, ecCw:26, size:29 },
    4: { dataCw:64, ecCw:36, size:33 },
    5: { dataCw:86, ecCw:48, size:37 },
    6: { dataCw:108, ecCw:64, size:41 },
    7: { dataCw:124, ecCw:72, size:45 },
    8: { dataCw:154, ecCw:88, size:49 },
    9: { dataCw:182, ecCw:110, size:53 },
    10:{ dataCw:216, ecCw:130, size:57 }
  };

  function chooseVersion(byteLen){
    // byte mode overhead: mode(4) + len(8/16) + terminator/pad
    for (let v=1; v<=10; v++){
      const cap = QR_TABLE_M[v].dataCw * 8;
      // rough upper bound: 4 + (v<=9?8:16) + byteLen*8 + 4
      const need = 4 + (v<=9?8:16) + byteLen*8 + 4;
      if (need <= cap) return v;
    }
    return 10;
  }

  function pushBits(bitArr, value, bitCount){
    for (let i=bitCount-1;i>=0;i--){
      bitArr.push((value >> i) & 1);
    }
  }

  function bitsToBytes(bits){
    const out = [];
    for (let i=0;i<bits.length;i+=8){
      let b = 0;
      for (let j=0;j<8;j++){
        b = (b<<1) | (bits[i+j] ? 1 : 0);
      }
      out.push(b);
    }
    return out;
  }

  function buildCodewords(dataBytes){
    const version = chooseVersion(dataBytes.length);
    const t = QR_TABLE_M[version];
    const bits = [];

    // Mode: byte (0100)
    pushBits(bits, 0x4, 4);

    // Length field: v<=9 => 8 bits else 16 bits
    pushBits(bits, dataBytes.length, version <= 9 ? 8 : 16);

    // Data
    for (let i=0;i<dataBytes.length;i++) pushBits(bits, dataBytes[i], 8);

    // Terminator up to 4 zeros
    const maxBits = t.dataCw * 8;
    const remaining = maxBits - bits.length;
    pushBits(bits, 0, Math.min(4, Math.max(0, remaining)));

    // Pad to byte boundary
    while (bits.length % 8 !== 0) bits.push(0);

    // Pad codewords 0xEC, 0x11
    const dataCw = bitsToBytes(bits);
    while (dataCw.length < t.dataCw){
      dataCw.push((dataCw.length % 2 === 0) ? 0xEC : 0x11);
    }

    // ECC
    const ecc = rsComputeECC(dataCw, t.ecCw);

    // Interleave not needed for these small single-block M versions 1-10 in this simplified table
    const all = dataCw.concat(ecc);

    return { version, size: t.size, codewords: all };
  }

  function makeMatrix(size){
    const m = new Array(size);
    for (let y=0;y<size;y++){
      m[y] = new Array(size).fill(null); // null = unset, 0/1 set
    }
    return m;
  }

  function setFinder(m, x, y){
    for (let dy=-1;dy<=7;dy++){
      for (let dx=-1;dx<=7;dx++){
        const xx = x+dx, yy=y+dy;
        if (xx<0||yy<0||yy>=m.length||xx>=m.length) continue;
        const on =
          (dx>=0&&dx<=6&&dy>=0&&dy<=6) &&
          (dx===0||dx===6||dy===0||dy===6|| (dx>=2&&dx<=4&&dy>=2&&dy<=4));
        m[yy][xx] = on ? 1 : 0;
      }
    }
  }

  function setTiming(m){
    const size = m.length;
    for (let i=8;i<size-8;i++){
      const v = (i % 2 === 0) ? 1 : 0;
      if (m[6][i] === null) m[6][i] = v;
      if (m[i][6] === null) m[i][6] = v;
    }
  }

  function reserveFormat(m){
    const size = m.length;
    // Around top-left finder
    for (let i=0;i<9;i++){
      if (m[8][i] === null) m[8][i] = 0;
      if (m[i][8] === null) m[i][8] = 0;
    }
    // Around top-right finder
    for (let i=0;i<8;i++){
      if (m[i][size-8] === null) m[i][size-8] = 0;
      if (m[8][size-1-i] === null) m[8][size-1-i] = 0;
    }
    // Around bottom-left finder
    for (let i=0;i<8;i++){
      if (m[size-8][i] === null) m[size-8][i] = 0;
      if (m[size-1-i][8] === null) m[size-1-i][8] = 0;
    }
    // Dark module (version 1+): fixed at (4*version+9, 8) => (size-8, 8)
    m[size-8][8] = 1;
  }

  function placeData(m, codewords){
    const size = m.length;
    let bitIdx = 0;
    const totalBits = codewords.length * 8;

    function getBit(){
      if (bitIdx >= totalBits) return 0;
      const cw = codewords[bitIdx >> 3];
      const b = (cw >> (7 - (bitIdx & 7))) & 1;
      bitIdx++;
      return b;
    }

    let x = size - 1;
    let y = size - 1;
    let dir = -1;

    while (x > 0){
      if (x === 6) x--; // skip timing column

      for (let i=0;i<size;i++){
        const yy = y + dir*i;
        for (let dx=0;dx<2;dx++){
          const xx = x - dx;
          if (m[yy][xx] !== null) continue;

          let v = getBit();

          // Mask pattern 0 (simple, deterministic): (row+col) % 2 == 0
          if ( ((yy + xx) & 1) === 0 ) v ^= 1;

          m[yy][xx] = v;
        }
      }

      y = y + dir*(size-1);
      dir = -dir;
      x -= 2;
    }
  }

  // Format info for EC=M and mask=0 (fixed)
  // QR format bits are BCH encoded. For EC=M (01) and mask=000 => format = 0b01000 => BCH => 0x5412 xor 0x000? (masked)
  // Precomputed for (EC=M, mask=0): 0x5412 (binary 101010000010010)
  const FORMAT_M_MASK0 = 0x5412;

  function setFormatBits(m){
    const size = m.length;
    let f = FORMAT_M_MASK0;

    function bit(i){ return (f >> i) & 1; }

    // top-left timing cross
    for (let i=0;i<=5;i++) m[8][i] = bit(14 - i);
    m[8][7] = bit(8);
    m[8][8] = bit(7);
    m[7][8] = bit(6);
    for (let i=0;i<=5;i++) m[5 - i][8] = bit(i);

    // top-right
    for (let i=0;i<8;i++) m[8][size-1-i] = bit(14 - i);

    // bottom-left
    for (let i=0;i<7;i++) m[size-1-i][8] = bit(6 - i);
  }

  function buildMatrix(text){
    const dataBytes = utf8Bytes(text);
    const { size, codewords } = buildCodewords(dataBytes);

    const m = makeMatrix(size);

    // Finders
    setFinder(m, 0, 0);
    setFinder(m, size-7, 0);
    setFinder(m, 0, size-7);

    // Separators already handled by finder writer with -1..7 ring

    // Timing
    setTiming(m);

    // Reserve format + dark module
    reserveFormat(m);

    // Data
    placeData(m, codewords);

    // Format bits
    setFormatBits(m);

    // Replace any remaining nulls with 0
    for (let y=0;y<size;y++){
      for (let x=0;x<size;x++){
        if (m[y][x] === null) m[y][x] = 0;
      }
    }
    return m;
  }

  function drawToCanvas(canvas, text, width){
    const m = buildMatrix(text);
    const size = m.length;
    const w = Math.max(64, (width|0) || 256);

    canvas.width = w;
    canvas.height = w;

    const ctx = canvas.getContext("2d");
    const scale = w / size;

    ctx.clearRect(0,0,w,w);
    ctx.fillStyle = "#fff";
    ctx.fillRect(0,0,w,w);

    ctx.fillStyle = "#000";
    for (let y=0;y<size;y++){
      for (let x=0;x<size;x++){
        if (m[y][x]){
          const xx = Math.floor(x * scale);
          const yy = Math.floor(y * scale);
          const ww = Math.ceil((x+1)*scale) - xx;
          const hh = Math.ceil((y+1)*scale) - yy;
          ctx.fillRect(xx, yy, ww, hh);
        }
      }
    }
  }

  // ---------- Compatibility wrapper (qrcode@1.x-ish) ----------
  // QRCode.toCanvas(canvasOrEl, text, opts?, cb?)
  const QRCode = {
    toCanvas: function(target, text, opts, cb){
      try{
        if (typeof opts === "function"){ cb = opts; opts = null; }
        opts = opts || {};

        let canvas = target;
        if (typeof target === "string"){
          const el = document.getElementById(target);
          if (!el) throw new Error("toCanvas target id not found: " + target);
          canvas = el;
        }

        // If they pass a div, insert a canvas
        if (canvas && canvas.nodeType === 1 && canvas.tagName && canvas.tagName.toLowerCase() !== "canvas"){
          const host = canvas;
          host.innerHTML = "";
          canvas = document.createElement("canvas");
          host.appendChild(canvas);
        }

        if (!canvas || !canvas.getContext) throw new Error("toCanvas target is not a canvas (or host element)");

        const width = (opts && (opts.width || opts.size)) ? (opts.width || opts.size) : 256;
        drawToCanvas(canvas, String(text), width);

        if (cb) cb(null);
      }catch(e){
        if (cb) cb(e);
        else throw e;
      }
    }
  };

  global.QRCode = global.QRCode || QRCode;
})(typeof window !== "undefined" ? window : this);
